import{_ as n,C as p,c as i,o as l,j as s,G as t,a2 as r,a as o}from"./chunks/framework.DrNAj9nU.js";const d="/assets/invoice-1.rE00nr9z.png",_=JSON.parse('{"title":"为什么开发票要填公司抬头和税号？公司就一定能报销吗？","description":"","frontmatter":{},"headers":[],"relativePath":"column/CommonSense/生活常识/为什么发票填了公司就能报销？.md","filePath":"column/CommonSense/生活常识/为什么发票填了公司就能报销？.md","lastUpdated":1773135431000}'),c={name:"column/CommonSense/生活常识/为什么发票填了公司就能报销？.md"};function u(b,a,h,g,m,v){const e=p("ArticleMetadata");return l(),i("div",null,[a[0]||(a[0]=s("h1",{id:"为什么开发票要填公司抬头和税号-公司就一定能报销吗",tabindex:"-1"},[o("为什么开发票要填公司抬头和税号？公司就一定能报销吗？ "),s("a",{class:"header-anchor",href:"#为什么开发票要填公司抬头和税号-公司就一定能报销吗","aria-label":'Permalink to "为什么开发票要填公司抬头和税号？公司就一定能报销吗？"'},"​")],-1)),t(e),a[1]||(a[1]=r('<nav class="table-of-contents"><ul><li><a href="#一、什么是发票抬头">一、什么是发票抬头</a></li><li><a href="#二、为什么公司报销必须填写公司抬头">二、为什么公司报销必须填写公司抬头</a></li><li><a href="#三、为什么填公司抬头就可以报销">三、为什么填公司抬头就可以报销</a></li><li><a href="#四、填了公司抬头-也不一定能报销">四、填了公司抬头，也不一定能报销</a><ul><li><a href="#_1-发票内容不符合公司制度">1. 发票内容不符合公司制度</a></li><li><a href="#_2-发票类型不符合要求">2. 发票类型不符合要求</a></li><li><a href="#_3-发票不合法">3. 发票不合法</a></li></ul></li><li><a href="#五、为什么公司一定要发票">五、为什么公司一定要发票</a></li><li><a href="#六、为什么很多平台都要填写-发票抬头-税号">六、为什么很多平台都要填写“发票抬头+税号”</a></li></ul></nav><p><img src="'+d+`" alt="发票抬头和税号" loading="lazy"></p><p>很多人开发票时都会遇到一个问题：</p><blockquote><p>只要填了公司的 <strong>发票抬头 + 税号</strong>，公司就一定能报销吗？</p></blockquote><p>答案是：<strong>不一定。</strong></p><p>填写公司抬头和税号，只是 <strong>具备了报销的基础条件</strong>，但最终能不能报销，还要看很多因素。</p><p>下面用最简单的方式，把这件事讲清楚。</p><h2 id="一、什么是发票抬头" tabindex="-1">一、什么是发票抬头 <a class="header-anchor" href="#一、什么是发票抬头" aria-label="Permalink to &quot;一、什么是发票抬头&quot;">​</a></h2><p><strong>发票抬头，就是发票开给谁的名字。</strong></p><p>例如：</p><p>个人消费：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票抬头：张三</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>公司消费：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票抬头：上海某某科技有限公司</span></span>
<span class="line"><span>纳税人识别号：9131XXXXXXXXXXXX</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果是公司报销，一般都需要填写：</p><ul><li><strong>公司名称（发票抬头）</strong></li><li><strong>纳税人识别号（税号）</strong></li></ul><p>这两项信息。</p><h2 id="二、为什么公司报销必须填写公司抬头" tabindex="-1">二、为什么公司报销必须填写公司抬头 <a class="header-anchor" href="#二、为什么公司报销必须填写公司抬头" aria-label="Permalink to &quot;二、为什么公司报销必须填写公司抬头&quot;">​</a></h2><p>公司报销的本质，其实是 <strong>财务做账和税务合规</strong>。</p><p>根据税务规定，一张企业入账的发票必须证明四件事：</p><p>1️⃣ <strong>谁买的（购买方）</strong> 2️⃣ <strong>买了什么（商品或服务）</strong> 3️⃣ <strong>金额多少</strong> 4️⃣ <strong>发票是否合法</strong></p><p>如果发票是这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票抬头：张三</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>那从税务角度看，这笔消费就是：</p><p><strong>张三的个人消费。</strong></p><p>而不是公司的支出。</p><p>因此公司就无法：</p><ul><li>作为企业成本入账</li><li>抵扣企业所得税</li><li>进行税务合规记账</li></ul><p>所以很多公司会直接规定：</p><blockquote><p><strong>个人抬头发票，一律不能报销。</strong></p></blockquote><h2 id="三、为什么填公司抬头就可以报销" tabindex="-1">三、为什么填公司抬头就可以报销 <a class="header-anchor" href="#三、为什么填公司抬头就可以报销" aria-label="Permalink to &quot;三、为什么填公司抬头就可以报销&quot;">​</a></h2><p>如果发票是这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票抬头：上海某某科技有限公司</span></span>
<span class="line"><span>纳税人识别号：9131XXXXXXXX</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>那就代表：</p><p><strong>这笔消费是公司产生的费用。</strong></p><p>财务就可以把这笔费用计入企业成本。</p><p>例如员工买办公用品：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票抬头：上海某某科技有限公司</span></span>
<span class="line"><span>金额：200元</span></span>
<span class="line"><span>内容：办公用品</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>财务做账时会记录：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>借：管理费用 200</span></span>
<span class="line"><span>贷：现金 / 银行 200</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样企业就完成了一笔 <strong>成本入账</strong>。</p><h2 id="四、填了公司抬头-也不一定能报销" tabindex="-1">四、填了公司抬头，也不一定能报销 <a class="header-anchor" href="#四、填了公司抬头-也不一定能报销" aria-label="Permalink to &quot;四、填了公司抬头，也不一定能报销&quot;">​</a></h2><p>很多人以为：</p><blockquote><p>只要发票写公司名字就能报销。</p></blockquote><p>其实并不是。</p><p>即使抬头正确，也可能 <strong>无法报销</strong>。</p><p>常见原因有三个。</p><h3 id="_1-发票内容不符合公司制度" tabindex="-1">1. 发票内容不符合公司制度 <a class="header-anchor" href="#_1-发票内容不符合公司制度" aria-label="Permalink to &quot;1. 发票内容不符合公司制度&quot;">​</a></h3><p>例如员工开了这样一张发票：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票内容：香烟</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>很多公司的报销制度规定：</p><p>以下消费不能报销：</p><ul><li>香烟</li><li>个人消费</li><li>娱乐消费</li><li>与工作无关的费用</li></ul><p>因此财务可能直接拒绝报销。</p><h3 id="_2-发票类型不符合要求" tabindex="-1">2. 发票类型不符合要求 <a class="header-anchor" href="#_2-发票类型不符合要求" aria-label="Permalink to &quot;2. 发票类型不符合要求&quot;">​</a></h3><p>公司报销通常要求 <strong>正规发票</strong>。</p><p>例如：</p><ul><li>增值税普通发票</li><li>增值税专用发票</li></ul><p>如果只是：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>收据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这种一般 <strong>无法入账</strong>。</p><p>所以公司也无法报销。</p><h3 id="_3-发票不合法" tabindex="-1">3. 发票不合法 <a class="header-anchor" href="#_3-发票不合法" aria-label="Permalink to &quot;3. 发票不合法&quot;">​</a></h3><p>例如：</p><ul><li>假发票</li><li>发票金额异常</li><li>发票重复报销</li></ul><p>很多公司现在都会通过 <strong>国家税务系统查验发票</strong>。</p><p>如果发票查验失败，也不能报销。</p><h2 id="五、为什么公司一定要发票" tabindex="-1">五、为什么公司一定要发票 <a class="header-anchor" href="#五、为什么公司一定要发票" aria-label="Permalink to &quot;五、为什么公司一定要发票&quot;">​</a></h2><p>很多人会问：</p><blockquote><p>为什么公司报销一定要发票？</p></blockquote><p>原因其实只有一个：</p><p><strong>税务合规。</strong></p><p>举个简单例子。</p><p>假设一家公司一年收入：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果没有任何成本发票：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>利润 = 100万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>企业所得税：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100万 × 25% = 25万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但如果公司有很多成本发票：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>办公费 10万</span></span>
<span class="line"><span>服务器费 20万</span></span>
<span class="line"><span>差旅费 10万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>总成本：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>40万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>利润变成：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100 - 40 = 60万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>企业所得税：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>60万 × 25% = 15万</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>公司就 <strong>少交了10万税</strong>。</p><p>所以企业一定要通过发票来记录成本。</p><h2 id="六、为什么很多平台都要填写-发票抬头-税号" tabindex="-1">六、为什么很多平台都要填写“发票抬头+税号” <a class="header-anchor" href="#六、为什么很多平台都要填写-发票抬头-税号" aria-label="Permalink to &quot;六、为什么很多平台都要填写“发票抬头+税号”&quot;">​</a></h2><p>现在很多平台都会要求填写发票信息，比如：</p><ul><li>打车软件</li><li>电商平台</li><li>SaaS服务</li><li>云服务器</li></ul><p>通常填写内容是：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发票类型：企业</span></span>
<span class="line"><span>发票抬头：上海某某科技有限公司</span></span>
<span class="line"><span>税号：9131XXXXXXXX</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>系统就会自动生成发票：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>购买方：上海某某科技有限公司</span></span>
<span class="line"><span>纳税人识别号：9131XXXXXXXX</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>员工下载发票后，就可以提交公司报销。</p>`,97))])}const C=n(c,[["render",u]]);export{_ as __pageData,C as default};
